+    if (std.mem.startsWith(u8, pattern, "*.")) {
+        const suffix = pattern[1..]; // ".example.com"
+        // Find first dot in hostname
+        if (std.mem.indexOf(u8, hostname, ".")) |dot_idx| {
+            const host_suffix = hostname[dot_idx..];
